+    .describe('Claim expiration time in milliseconds'),
+});
+
+const issueReleaseSchema = z.object({
+  issueId: z.string().min(1).describe('Issue ID to release'),
+  claimantId: z.string().min(1).describe('ID of the current claimant'),
