+    let weightedCount = 0;
+    for (const claim of claims) {
+      const weight = priorityWeights[claim.priority] || 1.0;
+      // Blocked claims count less toward utilization
+      const blockFactor = claim.status === 'blocked' ? 0.5 : 1.0;
