+      success: true,
+      claim,
+      previousClaimant,
+      contestWindowEndsAt,
+    };
+  }
+
+  // ===========================================================================
+  // Get Stealable
+  // ===========================================================================
+
+  /**
+   * Get list of stealable issues, optionally filtered by agent type
+   */
+  async getStealable(agentType?: AgentType): Promise<IssueClaimWithStealing[]> {
+    const stealableClaims = await this.repository.findStealable(agentType);
