+    return staleClaims;
+  }
+
+  // ===========================================================================
+  // Auto Mark Stealable
+  // ===========================================================================
+
+  /**
+   * Auto-mark stealable work based on config thresholds
+   */
+  async autoMarkStealable(config: WorkStealingConfig): Promise<number> {
+    const staleClaims = await this.detectStaleWork(config);
+    const now = new Date();
+    let markedCount = 0;
