+
+    for (const [type1, type2] of config.crossTypeStealRules) {
+      if (ownerType === type1) allowedTypes.push(type2);
+      if (ownerType === type2) allowedTypes.push(type1);
+    }
+
+    return [...new Set(allowedTypes)];
+  }
