+/**
+ * Claim Domain Events (ADR-007)
+ *
+ * Domain events for the claims system following event sourcing pattern.
+ * All state changes emit events for audit trail and projections.
+ *
+ * @module v3/claims/domain/events
+ */
+
+import type {
+  ClaimId,
+  IssueId,
+  Claimant,
+  ClaimStatus,
+} from './types.js';
+
+// =============================================================================
+// Base Claim Event
+// =============================================================================
+
+/**
+ * Base interface for all claim domain events
+ */
+export interface ClaimDomainEvent {
+  /** Unique event identifier */
+  id: string;
+
+  /** Event type discriminator */
+  type: ClaimEventType;
+
+  /** Aggregate ID (claim ID) */
+  aggregateId: string;
+
+  /** Aggregate type - always 'claim' for this domain */
+  aggregateType: 'claim';
+
+  /** Event version for ordering */
+  version: number;
+
+  /** Timestamp when event occurred */
+  timestamp: number;
+
+  /** Event source */
+  source: string;
+
+  /** Event payload data */
+  payload: Record<string, unknown>;
+
+  /** Optional metadata */
+  metadata?: Record<string, unknown>;
+
+  /** Optional causation ID (event that caused this event) */
+  causationId?: string;
+
+  /** Optional correlation ID (groups related events) */
+  correlationId?: string;
+}
+
+// =============================================================================
+// Event Types
+// =============================================================================
+
+export type ClaimEventType =
+  | 'claim:created'
+  | 'claim:released'
+  | 'claim:expired'
+  | 'claim:status-changed'
+  | 'claim:note-added'
+  | 'handoff:requested'
+  | 'handoff:accepted'
+  | 'handoff:rejected'
+  | 'review:requested'
+  | 'review:completed';
+
+// =============================================================================
+// Specific Event Interfaces
+// =============================================================================
+
+export interface ClaimCreatedEvent extends ClaimDomainEvent {
+  type: 'claim:created';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    claimant: Claimant;
+    claimedAt: number;
+    expiresAt?: number;
+  };
+}
+
+export interface ClaimReleasedEvent extends ClaimDomainEvent {
+  type: 'claim:released';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    claimant: Claimant;
+    releasedAt: number;
+    reason?: string;
+  };
+}
+
+export interface ClaimExpiredEvent extends ClaimDomainEvent {
+  type: 'claim:expired';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    claimant: Claimant;
+    expiredAt: number;
+    lastActivityAt: number;
+  };
+}
+
+export interface ClaimStatusChangedEvent extends ClaimDomainEvent {
+  type: 'claim:status-changed';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    previousStatus: ClaimStatus;
+    newStatus: ClaimStatus;
+    changedAt: number;
+    note?: string;
+  };
+}
+
+export interface ClaimNoteAddedEvent extends ClaimDomainEvent {
+  type: 'claim:note-added';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    note: string;
+    addedAt: number;
+    addedBy: Claimant;
+  };
+}
+
+export interface HandoffRequestedEvent extends ClaimDomainEvent {
+  type: 'handoff:requested';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    handoffId: string;
+    from: Claimant;
+    to: Claimant;
+    reason: string;
+    requestedAt: number;
+  };
+}
+
+export interface HandoffAcceptedEvent extends ClaimDomainEvent {
+  type: 'handoff:accepted';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    handoffId: string;
+    from: Claimant;
+    to: Claimant;
+    acceptedAt: number;
+  };
+}
+
+export interface HandoffRejectedEvent extends ClaimDomainEvent {
+  type: 'handoff:rejected';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    handoffId: string;
+    from: Claimant;
+    to: Claimant;
+    rejectedAt: number;
+    reason: string;
+  };
+}
+
+export interface ReviewRequestedEvent extends ClaimDomainEvent {
+  type: 'review:requested';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    reviewers: Claimant[];
+    requestedAt: number;
+    requestedBy: Claimant;
+  };
+}
+
+export interface ReviewCompletedEvent extends ClaimDomainEvent {
+  type: 'review:completed';
+  payload: {
+    claimId: ClaimId;
+    issueId: IssueId;
+    reviewer: Claimant;
+    approved: boolean;
+    completedAt: number;
+    comments?: string;
+  };
+}
+
+// =============================================================================
+// Event Type Union
+// =============================================================================
+
+export type AllClaimEvents =
+  | ClaimCreatedEvent
+  | ClaimReleasedEvent
+  | ClaimExpiredEvent
+  | ClaimStatusChangedEvent
+  | ClaimNoteAddedEvent
+  | HandoffRequestedEvent
+  | HandoffAcceptedEvent
+  | HandoffRejectedEvent
+  | ReviewRequestedEvent
+  | ReviewCompletedEvent;
+
+// =============================================================================
+// Event Factory Functions
+// =============================================================================
+
+let eventCounter = 0;
+
+function generateEventId(): string {
+  return `claim-evt-${Date.now()}-${++eventCounter}`;
+}
+
+function createClaimEvent<T extends ClaimDomainEvent>(
+  type: T['type'],
+  aggregateId: string,
+  payload: T['payload'],
+  metadata?: Record<string, unknown>,
+  causationId?: string,
+  correlationId?: string
+): T {
+  return {
+    id: generateEventId(),
+    type,
+    aggregateId,
+    aggregateType: 'claim',
+    version: 1, // Version will be set by event store
+    timestamp: Date.now(),
+    source: 'claim-service',
+    payload,
+    metadata,
+    causationId,
+    correlationId,
+  } as T;
+}
+
+// =============================================================================
+// Public Event Factory Functions
+// =============================================================================
+
+export function createClaimCreatedEvent(
+  claimId: ClaimId,
+  issueId: IssueId,
+  claimant: Claimant,
+  expiresAt?: number
+): ClaimCreatedEvent {
+  return createClaimEvent('claim:created', claimId, {
+    claimId,
+    issueId,
+    claimant,
+    claimedAt: Date.now(),
+    expiresAt,
+  });
